@pytest.fixture
def user_factory(db):
    created = []
    def _create(**kwargs):
        defaults = {"name": "Test User", "email": f"user{len(created)}@example.com"}
        defaults.update(kwargs)
        user = User(**defaults)
        db.add(user)
        created.append(user)
        return user
    yield _create
    for u in created:
        db.delete(u)

describe('UserService', () => {
  let service: UserService;

  beforeEach(() => { service = new UserService(); });

  describe('createUser', () => {
    it('should create user with valid data', () => {
      const user = service.createUser({ name: 'John', email: 'john@example.com' });
      expect(user.id).toBeDefined();
      expect(user.name).toBe('John');
    });

    it('should throw for invalid email', () => {
      expect(() => service.createUser({ name: 'John', email: 'invalid' }))
        .toThrow('Invalid email');
    });
  });
});

